import os
from tensorflow.keras.models import load_model
from google.cloud import storage

# Get the model path from environment variable
MODEL_PATH = os.environ.get('MODEL_PATH')

# Initialize Google Cloud Storage client
client = storage.Client()

def get_latest_model(model_path):
    """Fetch and return the latest model version."""
    bucket_name, model_name = model_path.split('/')
    bucket = client.bucket(bucket_name)
    blobs = list(bucket.list_blobs(prefix=model_name))
    if not blobs:
        raise ValueError(f"No models found in {model_path}")
    
    # Get the latest blob (model) based on its name
    latest_blob = max(blobs, key=lambda x: int(x.name.split('_')[-1].split('.')[0]))
    return f"gs://{bucket_name}/{latest_blob.name}"

def load_model_from_cloud(model_path):
    """Load ML model from cloud storage."""
    latest_model_path = get_latest_model(model_path)
    model = load_model(latest_model_path)
    return model

